345	  private applyItemLibraryViewListFromApi(views: any[], def: { view_name: string } | null): void {
346	    if (views && views.length) {
347	      this.viewLayouts = views.map((v: any) => ({
348	        layout_name: v.view_name,
349	        is_default: !!v.is_default
350	      }));
351	    } else {
352	      this.viewLayouts = [{ layout_name: 'Default' }];
353	    }
354	    const defaultName = def?.view_name;
355	    const match = defaultName && this.viewLayouts.find((v) => v.layout_name === defaultName);
356	    this.selectedViewLayout = match || this.viewLayouts[0];
357	  }
358	
359	  applyTagsFilter(tags: string[]) {
360	    if (!this.gridApi) return;
361	    this.tagsQuery = (tags || []).join(' ');
362	    if (this.gridApi) {
363	      this.serverSideDatasource = this.createServerSideDatasource([]);
364	      this.gridApi.setGridOption("serverSideDatasource", this.serverSideDatasource);
365	    }
366	  }
367	
368	  async onSaveNewView(value) {
369	    if (!value || !value.trim()) return;
370	    
371	    const viewName = value.trim();
372	    this.viewLayouts.push({ layout_name: viewName, is_default: false });
373	    this.selectedViewLayout = { layout_name: viewName, is_default: false };
374	    
375	    const columnState = this.gridApi.getColumnState();
376	    const filterModel = this.gridApi.getFilterModel();
377	
378	    this.itemService.saveGridViewState({
379	      grid_id: 'itemLibrary',
380	      view_name: viewName,
381	      column_state: columnState,
382	      filter_model: filterModel
383	    }).subscribe(
384	      (data) => {
385	        this._snackBar.open(`View "${viewName}" was created successfully.`, 'close');
386	      },
387	      (error) => {
388	        this._snackBar.open(`Failed to save view. Please try again.`, 'close');
389	        console.error('Error saving grid view state:', error);
390	      }
391	    );
392	  }
393	
394	  onCreateNewItem = async () => {
395	    let href = document.location.href.split('/')
396	    const itemId = href[href.length - 1]
397	    const dialogRef = this.dialog.open(NewItemDialogComponent, {
398	      panelClass: 'create-new-item-dialog',
399	      width: 'min(1180px, calc(100vw - 48px))',
400	      maxWidth: 'calc(100vw - 48px)',
401	      maxHeight: 'calc(100vh - 48px)',
402	      data: {
403	        itemId: itemId
404	      }
405	    })
406	    dialogRef.afterClosed().subscribe(async (message) => {
407	      if (message) {
408	        // ✅ This is where SSRM takes over and fetches getAllitems
409	        if (this.gridApi) {
410	          this.gridApi.setGridOption("loading", true);
411	          this.gridApi.setGridOption("serverSideDatasource", this.createServerSideDatasource([]));
412	        }
413	      }
414	    })
415	  }
416	
417	  compareViewLayouts = (a: { layout_name: string } | null, b: { layout_name: string } | null): boolean =>
418	    a?.layout_name != null && b?.layout_name != null && a.layout_name === b.layout_name;
419	
420	  onViewChange(value) {
421	    this.selectedViewLayout = value;
422	    this.applyGridViewStateForViewName(value.layout_name);
423	  }
424	
425	  private applyGridViewStateForViewName(layoutName: string): void {
426	    if (!this.gridApi || !layoutName) {
427	      return;
428	    }
429	    this.itemService.getGridViewState({ grid_id: 'itemLibrary', view_name: layoutName }).subscribe((res: any) => {
430	      if (res) {
431	        if (res.column_state && res.column_state.length > 0) {
432	          this.gridApi.applyColumnState({ state: res.column_state, applyOrder: true });
433	        }
434	        if (res.filter_model) {
435	          setTimeout(() => {
436	            this.gridApi?.setFilterModel(res.filter_model);
437	          }, 200);
438	        }
439	      } else {
440	        this.itemService
441	          .getSelectedGridView({ layout_name: layoutName, grid_id: 'itemLibrary' })
442	          .subscribe(async (legacyRes: any) => {
443	            if (legacyRes.length > 0) {
444	              this.gridApi?.applyColumnState({ state: legacyRes, applyOrder: true });
445	            }
446	          });
447	      }
448	    });
449	  }
450	
451	  hasItemLibraryDefaultView(): boolean {
452	    return this.viewLayouts.some((v) => v.is_default);
453	  }
454	
455	  onSetItemLibraryViewAsDefault(): void {
456	    const v = this.selectedViewLayout;
457	    if (!v?.layout_name || v.layout_name === 'Default') {
458	      return;
459	    }
460	    this.itemService.setGridDefaultView({ grid_id: 'itemLibrary', view_name: v.layout_name }).subscribe({
461	      next: () => {
462	        this.viewLayouts = this.viewLayouts.map((x) => ({
463	          ...x,
464	          is_default: x.layout_name === v.layout_name
465	        }));
466	        this.selectedViewLayout =
467	          this.viewLayouts.find((x) => x.layout_name === v.layout_name) ?? this.selectedViewLayout;
468	        this._snackBar.open('This view will load by default when you open Item Library.', 'close');
469	      },
470	      error: (err) => {
471	        this._snackBar.open(err?.error?.message || 'Could not set default view.', 'close');
472	      }
473	    });
474	  }
475	
476	  onClearItemLibraryDefaultView(): void {
477	    this.itemService.setGridDefaultView({ grid_id: 'itemLibrary', clear: true }).subscribe({
478	      next: () => {
479	        this.viewLayouts = this.viewLayouts.map((x) => ({ ...x, is_default: false }));
480	        this._snackBar.open('Custom default cleared. Global Default will load on next visit.', 'close');
481	      },
482	      error: (err) => {
483	        this._snackBar.open(err?.error?.message || 'Could not clear default view.', 'close');
484	      }
485	    });
486	  }
487	
488	  async onSaveLayout(selectedView) {
489	    if (selectedView.layout_name !== 'Default' && selectedView.layout_name != null) {
490	      const columnState = this.gridApi.getColumnState();
491	      const filterModel = this.gridApi.getFilterModel();
492	      this.itemService.saveGridViewState({
493	        grid_id: 'itemLibrary',
494	        view_name: selectedView.layout_name,
495	        column_state: columnState,
496	        filter_model: filterModel
497	      }).subscribe(
498	        (data) => {
499	          this._snackBar.open(`Current view was saved successfully.`, 'close');
500	        },
501	        (error) => {
502	          this._snackBar.open(`Failed to save view. Please try again.`, 'close');
503	          console.error('Error saving grid view state:', error);
504	        }
505	      );
506	    } else {
507	      this._snackBar.open(`You can't save on Default view. Please select a different view or create a new one.`, 'close')
508	    }
509	  }
510	
511	  compareFeedbacks = (oldFeedback, newfeedback) => {
512	    for (let i = 0; i < oldFeedback.length; i++) {
513	      if (oldFeedback[i]?.status.toLowerCase() === newfeedback?.status.toLowerCase() && oldFeedback[i]?.from?.toLowerCase() === newfeedback?.from?.toLowerCase() && oldFeedback[i]?.package === newfeedback?.package) {
514	        newfeedback.id = oldFeedback[i].id
515	      }
516	    }
517	  }
518	
519	  openBulkDialog(phase) {
520	    // Get the selected 'package' and 'from' context menu options
521	    const type = document.getElementsByClassName('ag-menu-option-active')[1]?.textContent;
522	    const from = document.getElementsByClassName('ag-menu-option-active')[3]?.textContent;
523	
524	    const dialogRef = this.dialog.open(BulkUpdateComponent, {
525	      disableClose: true,
526	      width: '700px',
527	      data: { from: from, package: type, phase: phase.phase, status: phase.status }
528	    })
529	
530	
531	    dialogRef.afterClosed().subscribe(async (data) => {
532	      if (data) {
533	        const rows = this.gridApi.getSelectedRows();
534	        const mergedData = [];
535	        const ids = [];
536	
537	        if (!this.merchGroups) {
538	          const res = await this.itemService.getMerchGroup({ divisionCode: 1, DivisionStatus: 1 }).pipe(first()).toPromise();
539	          this.merchGroups = res[0]?.merchGroupHeaders;
540	        }
541	
542	        rows.forEach((row) => {
543	          ids.push(row.id.toString())
544	        })
545	
546	        let newData = JSON.parse(JSON.stringify(data));
547	        const licenses = await <any>this.ItemDetailService.BulkGetLicensingStatus(ids).pipe(first()).toPromise()
548	
549	        rows.forEach((row) => {
550	          if (licenses[row.id.toString()]) {
551	            const oldFeedback = licenses[row.id];
552	            // Add id field and update existing feedback if it already exists
553	            this.compareFeedbacks(oldFeedback, newData);
554	          }
555	
556	          newData.itemheader_id_fk = row.id.toString()
557	
558	          //Convert licensor code to full name
559	          if (newData?.from?.toLowerCase() !== 'pop') newData.from = this.merchGroups.find(g => g?.mgTypeDesc?.toLowerCase().replace(' ', '') === 'licensor')?.merchGroups.find(group => group?.mg_code === row?.licensor)?.mg_desc
560	          mergedData.push(JSON.parse(JSON.stringify(newData)))
561	        })
562	
563	
564	        this.ItemDetailService.BulkAddLicensingStatus(mergedData).subscribe((res: any) => {
565	          if (res.statusCode === 200) {
566	            this._snackBar.open(`Successfully bulk updated licenses!`, 'close')
567	          } else {
568	            this._snackBar.open(`An error occurred while updating licenses`, 'close')
569	          }
570	        })
571	      }
572	    })
573	  }
