724	
725	        if (!allMerchGroups.length) return null;
726	
727	        // Step 2: Find the correct group based on conditions
728	        if (m?.data?.is_item_old) {
729	          const matchedGroup = allMerchGroups.find(
730	            group =>
731	              group?.mg_code === m?.data[header] &&
732	              new Date(group?.createdTime).getFullYear() !== 2025
733	          );
