createServerSideDatasource(divisionCodeIds: number[]): IServerSideDatasource {
  const isArchive = this.currentUrl === 'archive';
  if (divisionCodeIds.length === 0) {
    divisionCodeIds = this.selectedDivisionCode?.map(d => d.divCode_id) || [];
  }
  return {
    getRows: (params: IServerSideGetRowsParams) => {
      const request = {
        startRow: params.request.startRow,
        endRow: params.request.endRow,
        filterModel: {
          ...(params.request.filterModel || {}),
          ...(this.tagsQuery ? { tags: { type: 'contains', filter: this.tagsQuery } } : {})
        },
        isArchive,
        divisionCodeIds
      };

      this.ItemLibraryService.getAllitems(request).subscribe({
        next: async (res: any) => {
          const rowData = res.rows || [];
          const totalCount = res.totalCount ?? rowData.length;

          this.rowData = rowData;
          this.totalRowCount = totalCount;

          const statusPanelComp = this.gridApi.getStatusPanel('customTotalCount');
          if (statusPanelComp) {
            (statusPanelComp as any).setTotalCount(totalCount);
          }

          this.gridApi.setGridOption("loading", false);
          this.decrementLoaderIfNeeded();

          params.success({
            rowData,
            rowCount: totalCount,
          });

          mergePreloadCellNotes(this.itemLibraryCellNotes, rowData, 'id');
          this.restoreStateFromSession();
        },
        error: (error) => {
          this.gridApi.setGridOption("loading", false);
          this.decrementLoaderIfNeeded();
          params.fail();
        }
      });
    }
  };
}
```

